  1→// Package fetch provides an HTTP fetcher with local archive caching for
  2→// downloading data source files used by the kapow import pipelines.
  3→package fetch
  4→
  5→import (
  6→	"archive/zip"
  7→	"bytes"
  8→	"compress/gzip"
  9→	"context"
 10→	"encoding/json"
 11→	"fmt"
 12→	"io"
 13→	"log/slog"
 14→	"net/http"
 15→	"os"
 16→	"os/exec"
 17→	"path/filepath"
 18→	"sort"
 19→	"strings"
 20→	"time"
 21→)
 22→
 23→// FetchConfig describes how to retrieve a data source file.
 24→type FetchConfig struct {
 25→	// Name is a short identifier (e.g. "nces") used in archive filenames.
 26→	Name string
 27→	// URL is the HTTP URL to download from.
 28→	URL string
 29→	// Format is the source format before re-compression: "csv", "csv.gz", "gz", "zip".
 30→	Format string
 31→}
 32→
 33→// cacheEntry is persisted as a JSON sidecar alongside each archive file.
 34→// It stores the HTTP cache validators from the last successful download so
 35→// that subsequent requests can use conditional GET (ETag / Last-Modified).
 36→type cacheEntry struct {
 37→	ETag         string `json:"etag,omitempty"`
 38→	LastModified string `json:"last_modified,omitempty"`
 39→	File         string `json:"file"` // absolute path to the .xz archive
 40→}
 41→
 42→// Fetcher downloads and caches source data files. It stores downloaded files
 43→// as xz-compressed archives in a local cache directory to avoid redundant
 44→// downloads across runs.
 45→type Fetcher struct {
 46→	cacheDir   string
 47→	httpClient *http.Client
 48→}
 49→
 50→// New creates a Fetcher that stores cached downloads in the given directory.
 51→func New(cacheDir string) *Fetcher {
 52→	return &Fetcher{
 53→		cacheDir:   cacheDir,
 54→		httpClient: &http.Client{},
 55→	}
 56→}
 57→
 58→// CacheDir returns the directory used for cached downloads.
 59→func (f *Fetcher) CacheDir() string {
 60→	return f.cacheDir
 61→}
 62→
 63→// Fetch retrieves the data source described by cfg, returning a reader over
 64→// the raw (decompressed) content. The caller is responsible for closing the
 65→// returned reader.
 66→//
 67→// Fetch logic:
 68→//  1. If no sidecar exists, check for manually-dropped archive files and
 69→//     return the newest one without hitting the network.
 70→//  2. Perform a conditional HTTP GET using ETag / Last-Modified from the
 71→//     sidecar when available.
 72→//  3. On 304 Not Modified, return the existing cached archive.
 73→//  4. On network error, fall back to the stale cached archive (if present)
 74→//     with a warning log.
 75→//  5. On 200 OK, decompress the source body, re-compress with xz -9e, save
 76→//     the archive and sidecar, and return the decompressed content.
 77→func (f *Fetcher) Fetch(ctx context.Context, cfg FetchConfig) (io.ReadCloser, error) {
 78→	if err := os.MkdirAll(f.cacheDir, 0o755); err != nil {
 79→		return nil, fmt.Errorf("fetch: create cache dir: %w", err)
 80→	}
 81→
 82→	storedExt := storedFormat(cfg.Format)
 83→	sidecarPath := filepath.Join(f.cacheDir, cfg.Name+".cache.json")
 84→	entry, _ := loadSidecar(sidecarPath)
 85→
 86→	// 1. When there is no sidecar, check for manually-dropped archive files.
 87→	//    This lets operators place hand-obtained files in the cache directory
 88→	//    for sources that cannot be downloaded automatically.
 89→	if entry == nil {
 90→		if path, ok := f.Latest(cfg.Name, storedExt); ok {
 91→			slog.Info("fetch: using manually-dropped file", "source", cfg.Name, "path", path)
 92→			return openXZ(ctx, path)
 93→		}
 94→	}
 95→
 96→	// 2. Build HTTP request, adding conditional headers from the sidecar.
 97→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, cfg.URL, nil)
 98→	if err != nil {
 99→		return nil, fmt.Errorf("fetch: build request: %w", err)
100→	}
101→	if entry != nil {
102→		if entry.ETag != "" {
103→			req.Header.Set("If-None-Match", entry.ETag)
104→		}
105→		if entry.LastModified != "" {
106→			req.Header.Set("If-Modified-Since", entry.LastModified)
107→		}
108→	}
109→
110→	resp, httpErr := f.httpClient.Do(req)
111→
112→	// 4. On network error, fall back to stale cache.
113→	if httpErr != nil {
114→		if entry != nil && entry.File != "" {
115→			if _, statErr := os.Stat(entry.File); statErr == nil {
116→				slog.Warn("fetch: network error, using stale cache",
117→					"source", cfg.Name, "file", entry.File, "error", httpErr)
118→				return openXZ(ctx, entry.File)
119→			}
120→		}
121→		return nil, fmt.Errorf("fetch: http get %s: %w", cfg.Name, httpErr)
122→	}
123→	defer resp.Body.Close()
124→
125→	// 3. Handle 304 Not Modified — content unchanged, return existing archive.
126→	if resp.StatusCode == http.StatusNotModified {
127→		if entry != nil && entry.File != "" {
128→			if _, statErr := os.Stat(entry.File); statErr == nil {
129→				slog.Info("fetch: content unchanged (304), using cached file",
130→					"source", cfg.Name, "file", entry.File)
131→				return openXZ(ctx, entry.File)
132→			}
133→		}
134→		return nil, fmt.Errorf("fetch: received 304 but no cached file for %s", cfg.Name)
135→	}
136→
137→	// Stale fallback for unexpected non-200 responses.
138→	if resp.StatusCode != http.StatusOK {
139→		if entry != nil && entry.File != "" {
140→			if _, statErr := os.Stat(entry.File); statErr == nil {
141→				slog.Warn("fetch: non-OK status, using stale cache",
142→					"source", cfg.Name, "status", resp.StatusCode, "file", entry.File)
143→				return openXZ(ctx, entry.File)
144→			}
145→		}
146→		return nil, fmt.Errorf("fetch: unexpected status %d for %s", resp.StatusCode, cfg.Name)
147→	}
148→
149→	// 5. Download: decompress source body, re-compress with xz, save archive.
150→	decompressed, err := decompressSource(resp.Body, cfg.Format)
151→	if err != nil {
152→		return nil, fmt.Errorf("fetch: decompress source %s: %w", cfg.Name, err)
153→	}
154→	defer decompressed.Close()
155→
156→	// Buffer the decompressed data so we can both archive it and return it.
157→	data, err := io.ReadAll(decompressed)
158→	if err != nil {
159→		return nil, fmt.Errorf("fetch: read body %s: %w", cfg.Name, err)
160→	}
161→
162→	archiveFile := filepath.Join(f.cacheDir,
163→		fmt.Sprintf("%s-%s.%s.xz", cfg.Name, time.Now().UTC().Format("2006-01-02"), storedExt))
164→
165→	if err := compressXZ(ctx, bytes.NewReader(data), archiveFile); err != nil {
166→		return nil, fmt.Errorf("fetch: compress archive %s: %w", cfg.Name, err)
167→	}
168→
169→	newEntry := &cacheEntry{
170→		ETag:         resp.Header.Get("ETag"),
171→		LastModified: resp.Header.Get("Last-Modified"),
172→		File:         archiveFile,
173→	}
174→	if err := saveSidecar(sidecarPath, newEntry); err != nil {
175→		slog.Warn("fetch: failed to save sidecar", "path", sidecarPath, "error", err)
176→	}
177→
178→	slog.Info("fetch: downloaded and archived",
179→		"source", cfg.Name, "file", archiveFile, "bytes", len(data))
180→
181→	return io.NopCloser(bytes.NewReader(data)), nil
182→}
183→
184→// Latest returns the path to the most recently dated archive file matching
185→// "{name}-*.{ext}.xz" in the cache directory. Returns ("", false) if none exist.
186→//
187→// Files are named with ISO dates (e.g. nces-2026-03-09.csv.xz) so lexicographic
188→// sort gives the correct newest-first order.
189→func (f *Fetcher) Latest(name, ext string) (string, bool) {
190→	pattern := filepath.Join(f.cacheDir, fmt.Sprintf("%s-*.%s.xz", name, ext))
191→	matches, err := filepath.Glob(pattern)
192→	if err != nil || len(matches) == 0 {
193→		return "", false
194→	}
195→	sort.Strings(matches)
196→	return matches[len(matches)-1], true
197→}
198→
199→// storedFormat returns the archive extension for a given source format,
200→// stripping any outer compression layer (e.g. "csv.gz" → "csv").
201→func storedFormat(format string) string {
202→	switch strings.ToLower(format) {
203→	case "csv.gz", "gz":
204→		return "csv"
205→	case "zip":
206→		return "csv"
207→	default:
208→		return format
209→	}
210→}
211→
212→// decompressSource wraps r in the appropriate decompressor for the source format.
213→// The caller is responsible for closing the returned ReadCloser.
214→func decompressSource(r io.Reader, format string) (io.ReadCloser, error) {
215→	switch strings.ToLower(format) {
216→	case "csv.gz", "gz":
217→		gr, err := gzip.NewReader(r)
218→		if err != nil {
219→			return nil, fmt.Errorf("open gzip reader: %w", err)
220→		}
221→		return gr, nil
222→
223→	case "zip":
224→		// archive/zip requires a ReaderAt; buffer the entire body first.
225→		data, err := io.ReadAll(r)
226→		if err != nil {
227→			return nil, fmt.Errorf("buffer zip body: %w", err)
228→		}
229→		zr, err := zip.NewReader(bytes.NewReader(data), int64(len(data)))
230→		if err != nil {
231→			return nil, fmt.Errorf("open zip: %w", err)
232→		}
233→		if len(zr.File) == 0 {
234→			return nil, fmt.Errorf("zip archive is empty")
235→		}
236→		rc, err := zr.File[0].Open()
237→		if err != nil {
238→			return nil, fmt.Errorf("open zip entry: %w", err)
239→		}
240→		return rc, nil
241→
242→	default:
243→		// Plain format (csv, tsv, …) — pass through unchanged.
244→		return io.NopCloser(r), nil
245→	}
246→}
247→
248→// compressXZ reads from src and writes an xz-compressed file to dst using the
249→// system xz binary with -9e (maximum/extreme compression).
250→func compressXZ(ctx context.Context, src io.Reader, dst string) error {
251→	f, err := os.Create(dst)
252→	if err != nil {
253→		return fmt.Errorf("create xz output: %w", err)
254→	}
255→	defer f.Close()
256→
257→	var stderr bytes.Buffer
258→	cmd := exec.CommandContext(ctx, "xz", "-9e", "-c") //nolint:gosec
259→	cmd.Stdin = src
260→	cmd.Stdout = f
261→	cmd.Stderr = &stderr
262→
263→	if err := cmd.Run(); err != nil {
264→		_ = os.Remove(dst)
265→		return fmt.Errorf("xz: %w: %s", err, strings.TrimSpace(stderr.String()))
266→	}
267→	return nil
268→}
269→
270→// openXZ returns a reader over the decompressed content of an xz archive using
271→// the system xz binary. The returned reader holds the entire decompressed
272→// content in memory.
273→func openXZ(ctx context.Context, path string) (io.ReadCloser, error) {
274→	var stderr bytes.Buffer
275→	cmd := exec.CommandContext(ctx, "xz", "-d", "-c", path) //nolint:gosec
276→	cmd.Stderr = &stderr
277→
278→	out, err := cmd.Output()
279→	if err != nil {
280→		return nil, fmt.Errorf("fetch: xz decompress %s: %w: %s",
281→			path, err, strings.TrimSpace(stderr.String()))
282→	}
283→	return io.NopCloser(bytes.NewReader(out)), nil
284→}
285→
286→// loadSidecar reads a cacheEntry from a JSON sidecar file.
287→// Returns (nil, err) if the file is absent or cannot be parsed.
288→func loadSidecar(path string) (*cacheEntry, error) {
289→	data, err := os.ReadFile(path)
290→	if err != nil {
291→		return nil, err
292→	}
293→	var entry cacheEntry
294→	if err := json.Unmarshal(data, &entry); err != nil {
295→		return nil, fmt.Errorf("fetch: unmarshal sidecar %s: %w", path, err)
296→	}
297→	return &entry, nil
298→}
299→
300→// saveSidecar writes a cacheEntry to a JSON sidecar file.
301→func saveSidecar(path string, entry *cacheEntry) error {
302→	data, err := json.MarshalIndent(entry, "", "  ")
303→	if err != nil {
304→		return fmt.Errorf("fetch: marshal sidecar: %w", err)
305→	}
306→	return os.WriteFile(path, data, 0o644) //nolint:gosec
307→}
