223→// DeriveOpinion parses a raw ranking string and returns the method, rank,
224→// score, and tier. Supported formats:
225→//   - Numeric ranks: "1", "42"
226→//   - Tier strings: "Tier 1", "Tier 2"
227→//   - Ranges: "201-300" (rank = midpoint, tier = original string)
228→//   - Decimal scores: "78.5"
229→func DeriveOpinion(raw string) (method string, rank int, score float64, tier string, err error) {
230→	raw = strings.TrimSpace(raw)
231→	if raw == "" {
232→		return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: empty input")
233→	}
234→
235→	// Tier format: "Tier N" or "Tier ..."
236→	if strings.HasPrefix(strings.ToLower(raw), "tier") {
237→		return "tier", 0, 0, raw, nil
238→	}
239→
240→	// Range format: "NNN-NNN"
241→	if parts := strings.SplitN(raw, "-", 2); len(parts) == 2 {
242→		lo, errLo := strconv.Atoi(strings.TrimSpace(parts[0]))
243→		hi, errHi := strconv.Atoi(strings.TrimSpace(parts[1]))
244→		if errLo == nil && errHi == nil && lo > 0 && hi > 0 {
245→			midpoint := int(math.Round(float64(lo+hi) / 2))
246→			return "range", midpoint, 0, raw, nil
247→		}
248→	}
249→
250→	// Integer rank
251→	if n, errInt := strconv.Atoi(raw); errInt == nil {
252→		return "rank", n, 0, "", nil
253→	}
254→
255→	// Decimal score
256→	if f, errFloat := strconv.ParseFloat(raw, 64); errFloat == nil {
257→		return "score", 0, f, "", nil
258→	}
259→
260→	return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: unrecognized format %q", raw)
261→}
